                if len(parts) != 2:
                    console.print(f"[red]Invalid header format '{header}'. Expected 'key:value'[/red]")
                    raise typer.Exit(code=1)
                headers[parts[0].strip()] = parts[1].strip()

        # Get endpoint URL
        endpoint, base_url = self._validate_invoke_prerequisites(workspace_path)

        # For AgentRuntime with k8s_deployment.type == "AgentRuntime"
