        else:
            raise ValueError("Could not determine endpoint URL. Ensure agent is published.")

        # Add session header if available
        if metadata.session_id:
            headers["X-AgentCube-Session-Id"] = metadata.session_id

        if self.verbose:
            console.print(f"[blue]Sending request to: {url}[/blue]")
            console.print(f"[blue]Headers: {headers}[/blue]")
            console.print(f"[blue]Payload: {json.dumps(json_payload, indent=2)}[/blue]")

