        """Validate invoke prerequisites."""
        metadata = MetadataService.load_metadata(str(workspace_path))
        if not metadata:
            raise ValueError("No metadata found")

        if not metadata.agent_id:
            raise ValueError("Agent not published. Run 'publish' first.")

        # Determine base URL
        base_url = None
        if metadata.router_url:
            base_url = metadata.router_url
        elif metadata.k8s_deployment and metadata.k8s_deployment.service_url:
            base_url = metadata.k8s_deployment.service_url
        elif metadata.agent_endpoint:
            base_url = metadata.agent_endpoint

        return metadata.agent_id, base_url


